/*
# Menu

The record-driven menu (planes.md §4–§6): items are DATA — the component
arranges; the author never composes rows. The standard record covers real OS
menus:

    { id, label, key?, enabled?, checked?, divider?, submenu?, kind?, props? }

- `key` renders right-aligned (display only — registration is the Keys
  service's, later).
- `enabled: false` dims the row (theme.disabledOpacity) and refuses pick.
- `{ divider: true }` is a separator line.
- `submenu: [ …records… ]` marks a cascade (the ▸ arrow; the cascade itself
  lands with the roving-keyboard stage).
- `kind: "ClassName"` renders the row's CONTENT with a named author class
  (app.createView — keep data-only classes with `use [ Name ]`), passed
  `props` as its datapath context. Behavior stays the row's: highlight,
  pick, keyboard are the menu's, always.

Declared ONCE, opened by many (the worked example): rows carry
`onContextMenu(e) { app.rowMenu.openAt(this, e) }`; the menu's `items`
constraint derives from `opener` — per-row variation with zero per-row
instances, live while open. `openAt` point-positions (the context-menu
rule); `openFor` drops below a control (the attached-menu rule); both
RAISE the menu (promotion — order is a slot) and clamp inside the app.

Dismissal: the BACKDROP (a full-app child under the panel) — a press
outside closes AND is swallowed, the Mac rule (planes.md §12.1, resolved
for v1); Escape closes; pick closes after delivery.
*/



class Menu extends View [ visible = { this.shown }, width = 220,
    height = { this.panel.height },              // the panel; the backdrop deliberately overflows

    items: array = null,
    opener: View = null,
    shown: boolean = false,

    // the cascade: ONE lazily-created child Menu (app.createView — a Menu
    // cannot declare a Menu child without recursing), reused across rows;
    // rootMenu threads to the chain's root (null ON the root). activeRow is
    // the keyboard rover's highlight. View-typed slots can't see Menu
    // members, so all child-driving goes through ANY-typed method params —
    // the untyped seam, used deliberately.

    isRoot: boolean = true,
    rootMenu: View = null,
    child: View = null,
    activeRow: View = null,

    // the delivery seam — the app overrides; the id is the whole message

    picked(id) { },

    openAt(v, e) {
        let x = e.x
        let y = e.y
        let n = v
        while (n != null) { x += n.x || 0; y += n.y || 0; n = n.parent }
        this.place(x, y)
        this.opener = v
        this.shown = true
        this.raise()
        },

    openFor(v) {
        let x = 0
        let y = 0
        let n = v
        while (n != null) { x += n.x || 0; y += n.y || 0; n = n.parent }
        this.place(x, y + v.height + 4)
        this.opener = v
        this.shown = true
        this.raise()
        },

    // place() takes ROOT-space targets (openAt/openFor compute them by
    // walking up) and converts to parent-space, so a Menu works declared at
    // App level OR inside a component (MenuBar owns one). The chain offset
    // is snapshotted at open — menu chrome doesn't move while a menu is up.

    offX: number = 0,
    offY: number = 0,

    place(x, y) {
        let px = 0
        let py = 0
        let n = this.parent
        while (n != null) { px += n.x || 0; py += n.y || 0; n = n.parent }
        this.offX = px
        this.offY = py
        this.x = Math.max(4, Math.min(this.root.width - this.width - 4, x)) - px
        this.y = Math.max(4, Math.min(this.root.height - this.height - 4, y)) - py
        },

    close() {
        this.closeSub()
        this.shown = false
        this.opener = null
        this.activeRow = null
        },

    pick(id) { this.picked(id); this.close() },

    // ── the cascade ────────────────────────────────────────────────────────

    openSub(row, subItems) {
        let x = 0
        let y = 0
        let n = row
        while (n != null) { x += n.x || 0; y += n.y || 0; n = n.parent }
        if (this.child == null) this.child = this.root.createView("Menu", this.root, ({ isRoot: false, rootMenu: this.rootMenu != null ? this.rootMenu : this }))
        this.driveSub(this.child, subItems, x + this.width - 6, y - 5)
        },

    driveSub(c, subItems, x, y) {
        c.items = subItems
        c.picked = (id) => this.pick(id)         // delivery + close route through the CHAIN to the root
        c.shown = true
        c.place(x, y)
        c.raise()
        },

    closeSub() { if (this.child != null) this.closeIt(this.child) },
    closeIt(c) { c.close() },
    subShown(c) { return c != null && c.shown },
    rootClose() { this.closeIt(this.rootMenu != null ? this.rootMenu : this) },

    // ── keyboard roving (the deepest shown menu handles the keys) ──────────

    rowsOf(b) { return b.children },

    step(d) {
        const rows = this.rowsOf(this.panel.body).filter((r) => !r.divider && r.enabled && r.custom == "")
        if (rows.length == 0) return
        const i = rows.indexOf(this.activeRow)
        this.activeRow = rows[i < 0 ? (d > 0 ? 0 : rows.length - 1) : (i + d + rows.length) % rows.length]
        },

    pickActive() { this.pickRow(this.activeRow) },

    pickRow(r) {
        if (r == null) return
        if (r.sub) { this.enterSub(); return }
        r.pickSelf()
        },

    enterSub() { this.enterRow(this.activeRow) },

    enterRow(r) {
        if (r == null || !r.sub) return
        r.openSelf()
        if (this.child != null) this.stepIn(this.child)
        },

    stepIn(c) { c.step(1) },

    onKeyDown(e) <- Keys {
        if (!this.shown) return
        if (this.subShown(this.child)) return          // the deeper menu handles
        if (e.key == "ArrowDown") this.step(1)
        else if (e.key == "ArrowUp") this.step(-1)
        else if (e.key == "Enter") this.pickActive()
        else if (e.key == "ArrowRight") this.enterSub()
        else if (e.key == "ArrowLeft") { if (!this.isRoot) this.close() }
        },

    onKeyUp(e) <- Keys {
        if (!this.shown || e.key != "Escape") return
        if (this.subShown(this.child)) return          // the deeper menu handles
        this.rootClose()                          // Escape closes the WHOLE chain (macOS)
        },

    // items → rows through an INTERNAL derived dataset (the author passes a
    // plain array — the no-dataset-requirement ruling; the wrap is ours)

    data: Dataset [ contents = { ({ rows: classroot.items || [] }) } ],

    // the backdrop: the light-dismiss stratum in embryonic form — a full-app
    // press-catcher UNDER the panel; outside presses close and are SWALLOWED

    back: View [ visible = { classroot.isRoot },
        x = { -classroot.x - classroot.offX }, y = { -classroot.y - classroot.offY },
        width = { this.root.width }, height = { this.root.height },
        onMouseDown() { classroot.rootClose() },
        ],

    // the panel

    panel: View [ width = { classroot.width },
        height = { this.body.contentHeight + 10 },
        cornerRadius = { typeof this.theme.menuRadius == "number" ? this.theme.menuRadius : 8 },
        fill = { this.theme.surface },
        stroke = { stroke(1, this.theme.line) },
        shadow = { this.theme.menuShadow != null ? this.theme.menuShadow : shadow(0, 10, 40, 0x00000038) },

        body: View [ x = 0, y = 5, width = { parent.width },
            layout: SimpleLayout [ axis = y, spacing = 0 ],
            datapath = { classroot.data.value },

            View [ datapath = :rows[], width = { parent.width },
                divider:  boolean = { !!:divider },
                enabled:  boolean = { :enabled != false },
                sub:      boolean = { !!:submenu },
                custom:   string  = { typeof :kind == "string" ? "" + :kind : "" },
                hovered:  boolean = false,
                height = { this.divider ? 9 : this.custom != "" ? Math.max(26, this.host.height + 8) : 26 },
                opacity = { this.enabled ? 1 : (typeof this.theme.disabledOpacity == "number" ? this.theme.disabledOpacity : 0.45) },

                onMouseOver() {
                    if (!this.enabled || this.divider) return
                    this.hovered = true
                    classroot.activeRow = null           // the mouse takes over from the rover
                    if (this.sub) classroot.openSub(this, :submenu)
                    else classroot.closeSub()
                    },
                onMouseOut()  { this.hovered = false },

                // the rover's verbs — written on the row so :id / :submenu
                // resolve against THIS row's record

                pickSelf() { classroot.pick("" + :id) },
                openSelf() { classroot.openSub(this, :submenu) },

                // a `kind` row owns its own interior interactivity (the Finder
                // tag-dots idiom): no row-level pick, no row highlight — the
                // content's elements claim their own clicks (deepest sink wins)

                onClick() { if (this.enabled && !this.divider && !this.sub && this.custom == "") classroot.pick("" + :id) },

                onInit() {
                    if (this.custom != "") this.root.createView(this.custom, this.host, ({ datapath: :props }))
                    },

                // the hover highlight — inset, rounded, accent (the Mac read)

                hl: View [ x = 5, y = 1, width = { parent.width - 10 }, height = { parent.height - 2 },
                    cornerRadius = 5, visible = { (parent.hovered || classroot.activeRow == parent) && parent.custom == "" },
                    fill = { this.theme.menuHl != null ? this.theme.menuHl : this.theme.accent } ],

                rule: View [ x = 10, y = 4, width = { parent.width - 20 }, height = 1,
                    visible = { parent.divider }, fill = { this.theme.line } ],

                check: Text [ x = 8, y = center, fontSize = 12, visible = { !parent.divider && !!:checked },
                    textColor = { (parent.hovered || classroot.activeRow == parent) ? (this.theme.menuHlText != null ? this.theme.menuHlText : this.theme.accentText) : this.theme.text }, text = "✓" ],

                lbl: Text [ x = 24, y = center, fontSize = 13, visible = { !parent.divider && parent.custom == "" },
                    textColor = { (parent.hovered || classroot.activeRow == parent) ? (this.theme.menuHlText != null ? this.theme.menuHlText : this.theme.accentText) : this.theme.text },
                    text = { "" + (:label || "") } ],

                key: Text [ y = center, fontSize = 12,
                    x = { parent.width - this.width - 12 },
                    visible = { !parent.divider && !parent.sub && :key != null },
                    textColor = { (parent.hovered || classroot.activeRow == parent) ? (this.theme.menuHlText != null ? this.theme.menuHlText : this.theme.accentText) : this.theme.textMuted },
                    text = { "" + (:key || "") } ],

                // the submenu chevron is DRAWN (the macOS rendition — larger and
                // more legible than any glyph; reactive draw, both backends)

                arrow: View [ width = 7, height = 11, visible = { parent.sub },
                    x = { parent.width - 17 }, y = { (parent.height - this.height) / 2 },
                    draw(d) {
                        const hov = this.parent.hovered || classroot.activeRow == this.parent
                        const c = hov ? (typeof this.theme.menuHlText == "number" ? this.theme.menuHlText : this.theme.accentText) : this.theme.textMuted
                        d.strokeStyle = c
                        d.lineWidth = 1.8
                        d.beginPath()
                        d.moveTo(1, 1.5)
                        d.lineTo(5.8, 5.5)
                        d.lineTo(1, 9.5)
                        d.stroke()
                        },
                    ],

                // a `kind` row's author-rendered content region

                host: View [ x = 24, y = 4, width = { parent.width - 34 },
                    visible = { parent.custom != "" } ],
                ],
            ],
        ],
    ]

/*
# MenuBar

The record-driven menu bar (planes.md §4–§6): whole menus are DATA —

    menus = { [ ({ id, label, bold?, items: [ …menu records… ] }), … ] }

— and the component arranges. ONE internal Menu serves every title; its
`items` constraint derives from the open title's record, so item state
(enabled, checked, labels) stays LIVE while the menu is up. Because the
records are the single declaration, an app can derive its key registry
from the same array the bar renders — nothing is declared twice (the
Newton keys direction, proven in apps/desktop).

Tracking is the macOS behavior: titles do NOT highlight on mere hover;
a click opens (and highlights) a title; while any menu is open, moving
across another title switches to it; clicking the open title closes.

Delivery is the one seam: `picked(id)` — override at the use site.
*/



class MenuBar extends View [ height = 25,

    menus: array = null,

    // the delivery seam — the id is the whole message

    picked(id) { },

    openId: string = "",
    shown: boolean = { this.menu.shown },

    width = { this.row.contentWidth },

    openMenu(t) {
        this.openId = "" + t.mid
        this.menu.openFor(t)
        // the menu self-raises, which lifts its full-app backdrop over the
        // titles — but macOS keeps the bar HOT while a menu is open (that is
        // what tracking is). Promote the row back above the backdrop; the
        // panel drops below the bar, so nothing occludes visually.
        this.row.raise()
        },

    // while open, crossing another title switches to it (menu tracking)

    trackMenu(t) { if (this.menu.shown && "" + t.mid != this.openId) this.openMenu(t) },

    // ── arrows walk the bar while a menu is open (macOS): Left/Right move to
    // the adjacent title's menu. The open Menu keeps the keys when a submenu
    // is up (Left backs out of it) or when the rover sits on a submenu row
    // (Right enters it) — the guards below yield exactly those cases.

    rowsOf() { return this.row.children },

    hasSub(r) { return r != null && r.sub == true },

    stepMenu(d) {
        const ms = this.menus || []
        const i = ms.findIndex((m) => "" + m.id == this.openId)
        if (i < 0 || ms.length < 2) return
        const nid = "" + ms[(i + d + ms.length) % ms.length].id
        const t = this.rowsOf().find((r) => "" + r.mid == nid)
        if (t != null) this.openMenu(t)
        },

    onKeyDown(e) <- Keys {
        if (!this.menu.shown) return
        if (this.menu.subShown(this.menu.child)) return
        if (e.key == "ArrowLeft") this.stepMenu(-1)
        else if (e.key == "ArrowRight") { if (!this.hasSub(this.menu.activeRow)) this.stepMenu(1) }
        },

    menu: Menu [
        items = { ((classroot.menus || []).find((m) => "" + m.id == classroot.openId) || ({ })).items || [] },
        picked(id) { classroot.picked(id) },
        ],

    data: Dataset [ contents = { ({ m: classroot.menus || [] }) } ],

    row: View [ height = { parent.height },
        layout: SimpleLayout [ axis = x, spacing = 2 ],
        datapath = { classroot.data.value },
        View [ datapath = :m[], height = { parent.height },
            mid: string = { "" + :id },
            open: boolean = { classroot.menu.shown && classroot.openId == this.mid },
            width = { this.t.width + 20 },
            cornerRadius = 5,
            fill = { this.open ? this.theme.controlActive : null },
            onMouseOver() { classroot.trackMenu(this) },
            onClick() { if (this.open) classroot.menu.close(); else classroot.openMenu(this) },
            t: Text [ x = 10, y = center, fontSize = 14,
                fontWeight = { :bold ? "bold" : "regular" },
                textColor = { this.theme.text }, text = { "" + :label } ],
            ],
        ],
    ]

/*
# Control

The interaction-state base every stateful control extends (docs/system-design/components-baseline.md,
Contract 3). It owns the INTERACTION states — how the pointer and focus relate to this
view — and nothing semantic: `checked`, `value`, and their kin live on the concrete
control. Wired once here, for everything that extends it:

- `hovered` / `pressed` — the rollover pair; `pressed` is the touch feedback (a touch
  pointer never hovers), and a `pointercancel` (the browser reclaimed the gesture for a
  scroll) arrives as the release, so a press can never stick.
- `disabled` — inert: not focusable, no state changes; concrete controls gate their
  activation on it.
- keyboard — Space or Enter on the focused control activates it, the same `press()`
  path a pointer uses.
*/

class Control extends View [
    hovered:  boolean = false,
    pressed:  boolean = false,
    disabled: boolean = false,
    focused:  boolean = false,

    // The :focus-visible channel for the control's OWN styling (a Tab header's
    // focus edge): focused AND the focus arrived by keyboard. Captured at the
    // focus event (the web's rule), cleared by blur — and by a pointer press on
    // this very control, the one case with no focus event (Focus.focus on the
    // already-focused target is a no-op, but the modality still cleared).

    focusVisible: boolean = false,

    focusable = { !this.disabled },

    // The keyboard affordance is the app-level FocusRing (focusring.declare —
    // one traveling indicator, declared once in the App), not a per-control
    // ring; `focused` stays declared here for controls' own styling.

    // the activation seam — concrete controls override; pointer and keyboard both land here

    press() { },

    // the control's FOCUS SILHOUETTE — override to ring something other than
    // the whole bounds (a Radio rings its dot). null = bounds + cornerRadius.
    // { x, y, w, h, rad } in the control's own coordinates.

    focusShape() { return null },

    // keyboard activation's visual acknowledgment: flash the pressed look
    // (the platform convention for buttons — and menu items, later). Value
    // controls whose state change IS the feedback (Checkbox, Switch, Radio)
    // don't call this. `flashMs` is per-control tunable.

    flashMs: number = 220,

    flashPress() {
        this.pressed = true
        setTimeout(() => { this.pressed = false }, this.flashMs)
        },

    onFocus() { this.focused = true; this.focusVisible = Focus.byKeyboard() },
    onBlur()  { this.focused = false; this.focusVisible = false },

    onMouseOver() { if (!this.disabled) this.hovered = true },
    onMouseOut()  { this.hovered = false; this.pressed = false },

    // a click is also a focus claim — the keyboard picks up where the pointer left

    onMouseDown() { if (!this.disabled) { this.pressed = true; this.focusVisible = false; Focus.focus(this) } },
    onMouseUp()   { this.pressed = false },
    onKeyDown(e) { if (!this.disabled && !e.repeat && (e.key == "Enter" || e.key == " ")) this.press() },
    ]

/*
# Button

A labeled action control. The action is its `onClick` — write it at the use site
exactly as on any View; `Button` adds the interaction states, the themed look, and
keyboard activation (Space/Enter drives the same `onClick`). `primary = true` fills
with the accent; the default is the quiet control look.
*/



class Button extends Control [
    height = { typeof this.theme.buttonHeight == "number" ? this.theme.buttonHeight : 40 },
    cornerRadius = { typeof this.theme.buttonRadius == "number" ? Math.min(this.theme.buttonRadius, this.height / 2) : this.theme.controlRadius },
    label:   string = "",
    primary: boolean = false,

    onClick() { },
    press()   { this.flashPress(); this.onClick() },     // keyboard activation shows the press

    width   = { this.cap.width + 32 },
    opacity = { this.disabled ? 0.45 : this.pressed ? 0.72 : 1 },
    fill    = { this.primary ? this.theme.accent : this.pressed || this.hovered ? this.theme.controlActive : this.theme.control },

    // platforms whose secondary buttons are BORDERED say so in the theme
    // (Cupertino's hairline, Fluent's 1px) — flat systems leave it null

    stroke  = { !this.primary && this.theme.buttonBorder != null ? stroke(1, this.theme.buttonBorder) : null },

    cap: Text [ x = center, y = center, wrap = false, fontWeight = semibold,
        textColor = { classroot.primary ? this.theme.accentText : this.theme.text }, text = { classroot.label } ],
    ]

/*
# FocusRing

The traveling focus indicator — the OpenLaszlo 3.4 `focusoverlay` line, on the
reactive core, at its third form: a SHAPE-HUGGING rounded outline whose
terminus reshapes to the focused control's own silhouette (library-charter §6
— the ring springs position, size, AND cornerRadius; a Radio's row ring, a
pill Switch's ring, and a text field's ring differ because the targets do).

The layered model (charter, ratified):

- **The fact** — the ring listens to Focus (`onFocusChange(v) <- Focus`) and
  tracks the target's root-space geometry on EVERY change, pointer or
  keyboard. A pointer focus PARKS the ring there silently (snap, no show) —
  so the next Tab's flight departs from the control the user just clicked,
  never from a stale perch.
- **Roles, theme-elected** — `theme.focusRing`: `"both"` (or `true`, the
  default) · `"travel"` (flight + the OL idle fade) · `"rest"` (no flight —
  the ring appears in place and stays) · `false` (no ring; the theme's
  components carry the at-rest indication — the invariant lives with the
  THEME+components pair). While keyboard modality holds and the role includes
  rest, the ring RESTS — no idle fade; a pointer press clears modality and
  the ring hides (web :focus-visible semantics).
- **The flight is the flourish** — `theme.focusAnimate = false` (the
  sampler's "Animate focus transitions" toggle) snaps every move; the
  underdamped travel is default-on.

It arrives automatically with any Control-descended component (the OL
`canvas.focusclass` default); declare your own `FocusRing [ ]` (or subclass)
to replace it. Pure chrome: never focusable, never a pointer target.
(v1 limits, recorded: root-space bounds are summed through the parent chain —
a scrolled container is not compensated; the silhouette is the target's
`cornerRadius` — a `focusShape()` override protocol arrives with the
emulation passes.)
*/

class FocusRing extends View [ opacity = 0,

    // where the ring is HEADED — written by the subscription; the springs chase

    tx: number = 0,
    ty: number = 0,
    tw: number = 0,
    th: number = 0,
    trad: number = 8,
    rad: number = 8,
    shown: boolean = false,
    placed: boolean = false,                     // has the ring EVER had a target to park on?

    // the OL idle fade — TRAVEL role only; a resting ring does not fade

    idle: boolean = false,
    gen:  number = 0,

    // role helpers over the theme election

    ringRole()  { const r = this.theme.focusRing; return r == false ? "off" : r == true || r == null ? "both" : r },
    restRole()  { const r = this.ringRole(); return r == "both" || r == "rest" },
    travelRole() { const r = this.ringRole(); return r == "both" || r == "travel" },

    snapTo() { this.x = this.tx; this.y = this.ty; this.width = this.tw; this.height = this.th; this.rad = this.trad },

    // the target's LIVE silhouette, root-space, from the service's follower —
    // tracked through the parent chain and focusShape(), so an arrow-keyed
    // slider thumb (or a reflowing layout) moves the resting ring with it.
    // The band sits OUTSIDE the silhouette: inner edge touching the control's
    // boundary (the Mac halo's hug), displaced by gap + half the stroke.

    onGeometry(g) <- Focus {
        if (g.root != this.root) return
        const gap = typeof this.theme.focusRingGap == "number" ? this.theme.focusRingGap : 0
        const lw = typeof this.theme.focusRingWidth == "number" ? this.theme.focusRingWidth : 3
        const iw = typeof this.theme.focusRingInnerWidth == "number" ? this.theme.focusRingInnerWidth : 0
        const off = gap + iw + lw / 2
        this.tx = g.x - off; this.ty = g.y - off; this.tw = g.w + 2 * off; this.th = g.h + 2 * off
        this.trad = g.rad + off
        // Only a FOCUS CHANGE flies. The same control moving under a resting
        // ring — a dragged slider thumb, a reflow — takes the ring with it
        // rigidly: the springs' targets just moved, so land them NOW. The
        // discriminator is target IDENTITY (a handler-scratch expando — not
        // reactive state, just the previous event's view for comparison).
        const prev = (this)._lastTarget
        ;(this)._lastTarget = g.view
        if (prev == g.view) this.snapTo()
        },

    onFocusChange(v) <- Focus {
        if (v == null) { this.shown = false; return }
        let n = v
        for (; n != null && n.parent != null; n = n.parent) { }
        // Another app on the page (an embedded preview) owns this target — its own
        // ring indicates it; this one stands down rather than chase foreign coordinates.
        if (n != this.root) { this.shown = false; return }
        // Pointer focus: PARK silently — geometry current, ring hidden. The next
        // keyboard flight departs from here (the just-clicked control).
        if (!Focus.byKeyboard()) { this.shown = false; this.snapTo(); this.placed = true; return }
        if (this.ringRole() == "off") { this.shown = false; return }
        // No flight when: the ring has never been placed, the theme suppressed
        // the flourish, or the role is rest-only (appear in place, stay).
        if (!this.placed || this.theme.focusAnimate == false || !this.travelRole()) this.snapTo()
        this.placed = true
        this.shown = true
        this.raise()          // chrome stays chrome: above whatever raised last (a Dialog, a Menu)
        // idle fade only for the travel-only role — a resting ring persists
        if (this.restRole()) { this.idle = false; return }
        this.gen = this.gen + 1
        const g = this.gen
        this.idle = false
        setTimeout(() => { if (this.gen == g) this.idle = true }, 1000)
        },

    // the travel: underdamped springs = motion toward the target + a little
    // arrival overshoot — the 3.4 bounce, by physics. The radius travels too:
    // the terminus reshapes to the control it surrounds.

    Spring [ attribute = x,      to = { classroot.tx }, stiffness = 220, damping = 16 ],
    Spring [ attribute = y,      to = { classroot.ty }, stiffness = 220, damping = 16 ],
    Spring [ attribute = width,  to = { classroot.tw }, stiffness = 220, damping = 18 ],
    Spring [ attribute = height, to = { classroot.th }, stiffness = 220, damping = 18 ],
    Spring [ attribute = rad,    to = { classroot.trad }, stiffness = 220, damping = 20 ],

    Spring [ attribute = opacity, to = { classroot.shown && !classroot.idle ? 0.9 : 0 }, stiffness = 90, damping = 20 ],

    visible = { this.opacity > 0.02 },

    // pure chrome: never a pointer target

    containsPoint(px, py) { return false },

    // the shape-hugging outline — a rounded rect at the sprung radius, drawn,
    // so it re-derives as the radius travels between silhouettes

    // the OL brackets and the shape-hugging outline are ONE rendition at two
    // coverages: four corner-anchored strokes whose straight arms extend
    // toward each edge's midpoint by cov ∈ (0..1]. cov = 1 → arms meet, a
    // closed outline; cov low → open corner brackets ("target sights").
    // Coverage is a pure function of DISTANCE from target, so the physics
    // does the choreography: a flight breaks the ring open mid-air and the
    // settle closes the sights around the new silhouette. Small targets skip
    // the bracket phase (a ring around a radio dot has no arms to open).

    draw(d) {
        const w = this.width, h = this.height
        const Q = Math.PI / 2
        const dist = Math.abs(this.x - this.tx) + Math.abs(this.y - this.ty) + Math.abs(this.width - this.tw) + Math.abs(this.height - this.th)
        const small = Math.min(w, h) < 40
        // Ruled 2026-07-17: the ring travels as a CLOSED outline, source shape
        // to destination shape — no bracket mode intervening. The sights
        // rendition survives behind `theme.focusSights = true` (data, not a
        // code path) for its possible return: fully open in motion, arms
        // sweeping shut inside the last 16px of settle.
        const cov = this.theme.focusSights == true && !small ? Math.max(0.22, 1 - dist / 16) : 1
        const lw = typeof this.theme.focusRingWidth == "number" ? this.theme.focusRingWidth : 3
        // The indicator is ONE band or TWO, by data: `focusRingInnerWidth` > 0
        // adds an inner stroke between the control and the outer one — the
        // Fluent (Redmond) two-tone focus rectangle, black over white. Both
        // passes are the same outline at different insets; the flight, the
        // sights, and the silhouette machinery are shared, not forked.
        const iw = typeof this.theme.focusRingInnerWidth == "number" ? this.theme.focusRingInnerWidth : 0
        const pass = (ins, lwp, color) => {
            const r = Math.max(1, Math.min(this.rad - ins, Math.min(w, h) / 2 - ins))
            const ax = Math.max(0, ((w - 2 * ins) / 2 - r) * cov)      // horizontal arm length
            const ay = Math.max(0, ((h - 2 * ins) / 2 - r) * cov)      // vertical arm length
            d.strokeStyle = color
            d.lineWidth = lwp
            d.beginPath()
            // each corner: arc + arms, inset symmetrically
            d.moveTo(ins + r + ax, ins); d.lineTo(ins + r, ins); d.arc(ins + r, ins + r, r, -Q, Math.PI, true); d.lineTo(ins, ins + r + ay)
            d.moveTo(w - ins - r - ax, ins); d.lineTo(w - ins - r, ins); d.arc(w - ins - r, ins + r, r, -Q, 0); d.lineTo(w - ins, ins + r + ay)
            d.moveTo(w - ins, h - ins - r - ay); d.lineTo(w - ins, h - ins - r); d.arc(w - ins - r, h - ins - r, r, 0, Q); d.lineTo(w - ins - r - ax, h - ins)
            d.moveTo(ins + r + ax, h - ins); d.lineTo(ins + r, h - ins); d.arc(ins + r, h - ins - r, r, Q, Math.PI); d.lineTo(ins, h - ins - r - ay)
            d.stroke()
            }
        pass(0, lw, typeof this.theme.focusColor == "number" ? this.theme.focusColor : this.theme.accent)
        if (iw > 0) pass((lw + iw) / 2, iw, typeof this.theme.focusRingInnerColor == "number" ? this.theme.focusRingInnerColor : this.theme.surface)
        },
    ]

/*
# The desktop

The layers phase's everything-at-once proof (planes.md §11): a
high-fidelity Mac desktop, in Declare, under the Cupertino theme. Two real
apps — "Finder" (a column browser over this repository's own
documentation) and "Viewer" (Markdown windows reading the actual .md
files via `format = "text"`) — plus the structural pieces every ruling in
the layers design exercises at once:

- WINDOWS are a layer: created imperatively (`app.createView` — planes.md
  §7), dragged by title bars and resized by edges/corner (the
  captured-pointer pattern), RAISED on activation (promotion — order is a
  slot), shaded/zoomed/closed by the traffic lights. The front window
  derives its look from `app.frontWin` — activation is one View-typed
  slot.
- The DOCK magnifies by LAYOUT, not paint: hovered icons' real widths
  grow from a pointer-derived constraint over their RESTING slot centers
  (the magnification source must not read the magnified geometry — that
  would be a feedback loop), so neighbors displace and the translucent
  plate's edges push outward, exactly as the real dock's do. Bottom
  anchored, running dots below, the label pill above.
- The MENU BAR is the record-driven Menu opened below its titles;
  commands route through one `command(id)` seam.

Icons are DRAWN (no bitmaps — the weather app's image-elimination
precedent); the open-source icon harvest, cursor styles for resize
affordance, and the vibrancy material are the recorded next passes.
*/

use [ FinderWindow, ViewerWindow, AppWindow ]

// ── a desktop window: chrome once, contents per subclass ─────────────────────

class Window extends View [ width = 560, height = 400, cornerRadius = 10, clip = true,
    fill = { this.theme.surface },
    stroke = { stroke(1, this.theme.line) },
    shadow = { this.root.frontWin == this ? shadow(0, 18, 48, 0x00000059) : shadow(0, 8, 24, 0x00000030) },

    title: string = "",
    active: boolean = { this.root.frontWin == this },

    // the macOS open animation, MEASURED (burst captures of a real file open,
    // 2026-07-18): the window zooms FROM THE FILE'S POSITION — ~15% scale at
    // the icon, ~95% within the first ~100ms, settled by ~230ms; a strong
    // ease-out. bornX/bornY carry the origin in window coords (-1 = no origin:
    // a new window zooms gently from its own center instead).

    bornX: number = -1,
    bornY: number = -1,
    bornFrom: View = null,                       // the view the open came from, for the RETURN trip
    pivotX = { this.bornX >= 0 ? this.bornX : this.width / 2 },
    pivotY = { this.bornY >= 0 ? this.bornY : this.height / 2 },
    born: Animator [ attribute = scale, from = { classroot.bornX >= 0 ? 0.15 : 0.85 }, to = 1,
        duration = 230, motion = cubicOut, started = true ],

    // …and the open runs in REVERSE on close: the window shrinks back to its
    // return spot — recomputed at close time from the origin view (the finder
    // may have moved), falling back to the birth snapshot if it's gone.

    closing: boolean = false,

    beginClose() {
        if (this.closing) return
        this.closing = true
        if (this.bornFrom != null) {
            let ox = this.bornFrom.width / 2
            let oy = this.bornFrom.height / 2
            let n = this.bornFrom
            let top = null
            while (n != null) { ox += n.x || 0; oy += n.y || 0; top = n; n = n.parent }
            if (top == this.root) { this.bornX = ox - this.x; this.bornY = oy - this.y - 25 }
            }
        this.die.start()
        },

    die: Animator [ attribute = scale, to = 0.15, duration = 200, motion = cubicIn,
        onStop() { this.root.reallyClose(classroot) },
        ],

    // drag/resize bookkeeping (the captured-move pattern: root-space anchors)

    px0: number = 0,
    py0: number = 0,
    wx0: number = 0,
    wy0: number = 0,
    wh0: number = 0,
    dragging: boolean = false,
    sizeMode: string = "",                       // "" | "r" | "b" | "rb"

    // shade (yellow) and zoom (green) remember what they displace

    shaded: boolean = false,
    zoomed: boolean = false,
    saveH: number = 0,
    saveX: number = 0,
    saveY: number = 0,
    saveW: number = 0,

    activate() { this.root.frontWin = this; this.raise() },
    onMouseDown() { this.activate() },

    // subclass content attaches AFTER the base's children, so any content that
    // reaches the window's edges would eat the resize strips' events — the
    // chrome re-promotes above everything (order is a slot). Subclasses that
    // override onInit call raiseChrome() themselves.

    raiseChrome() {
        this.edgeL.raise()
        this.edgeR.raise()
        this.edgeB.raise()
        this.cornerBL.raise()
        this.grip.raise()
        },

    onInit() { this.raiseChrome() },

    shadeToggle() {
        if (this.shaded) { this.height = this.saveH; this.shaded = false }
        else { this.saveH = this.height; this.height = 35; this.shaded = true }
        },

    zoomToggle() {
        if (this.zoomed) { this.x = this.saveX; this.y = this.saveY; this.width = this.saveW; this.height = this.saveH; this.zoomed = false }
        else {
            this.saveX = this.x; this.saveY = this.y; this.saveW = this.width; this.saveH = this.height
            this.x = 12; this.y = 8
            this.width = this.root.width - 24
            this.height = this.root.height - 130
            this.zoomed = true
            }
        },

    wl0: number = 0,                             // window x at size start (left-edge modes)

    beginSize(mode) {
        this.activate()
        this.sizeMode = "" + mode
        this.px0 = this.root.pointerX
        this.py0 = this.root.pointerY
        this.wx0 = this.width
        this.wh0 = this.height
        this.wl0 = this.x
        },

    // modes compose macOS's grabbable set: "l" | "r" | "b" | "lb" | "rb".
    // A left-edge drag keeps the RIGHT edge fixed: x follows the width.

    moveSize() {
        if (this.sizeMode == "") return
        const dx = this.root.pointerX - this.px0
        const dy = this.root.pointerY - this.py0
        if (this.sizeMode.indexOf("r") >= 0) this.width = Math.max(340, this.wx0 + dx)
        if (this.sizeMode.indexOf("l") >= 0) {
            const w = Math.max(340, this.wx0 - dx)
            this.x = this.wl0 + (this.wx0 - w)
            this.width = w
            }
        if (this.sizeMode.indexOf("b") >= 0) this.height = Math.max(120, this.wh0 + dy)
        },

    lightsHover: boolean = false,

    bar: View [ width = { parent.width }, height = 35,
        fill = { classroot.active
                ? (this.root.darkMode ? gradient(0x3B3B40, 0x2E2E32) : gradient(0xFAFAFC, 0xE6E6EA))
                : this.theme.bg },
        onMouseDown() {
            classroot.activate()
            classroot.dragging = true
            classroot.px0 = this.root.pointerX
            classroot.py0 = this.root.pointerY
            classroot.wx0 = classroot.x
            classroot.wy0 = classroot.y
            },
        onMouseMove() {
            if (!classroot.dragging) return
            classroot.x = Math.max(-200, Math.min(this.root.width - 60, classroot.wx0 + this.root.pointerX - classroot.px0))
            classroot.y = Math.max(0, Math.min(this.root.height - 90, classroot.wy0 + this.root.pointerY - classroot.py0))
            },
        onMouseUp() { classroot.dragging = false },

        // the traffic lights — all three real: close, shade, zoom. Grey when
        // the window is inactive. The rollover state belongs to the LIGHTS
        // BLOCK alone (the bounding rectangle of the three circles — David's
        // reference), not the bar: hovering it colorizes even an inactive
        // window's lights and surfaces the glyphs; the rest of the bar never
        // does.

        lights: View [ x = 13, y = 10.5, width = 54, height = 14,
            onMouseOver() { classroot.lightsHover = true },
            onMouseOut()  { classroot.lightsHover = false },
            close: TrafficLight [ x = 0, c = #EC6A5E, rim = #D25349, ink = #7B1006, sym = "close",
                on = { classroot.active || classroot.lightsHover }, showGlyph = { classroot.lightsHover },
                onMouseOver() { classroot.lightsHover = true },
                onMouseOut()  { classroot.lightsHover = false },
                onClick() { this.root.closeWin(classroot) },
                ],
            mini: TrafficLight [ x = 20, c = #F5BF4F, rim = #D9A340, ink = #8F5B00, sym = "min",
                on = { classroot.active || classroot.lightsHover }, showGlyph = { classroot.lightsHover },
                onMouseOver() { classroot.lightsHover = true },
                onMouseOut()  { classroot.lightsHover = false },
                onClick() { classroot.shadeToggle() },
                ],
            zoom: TrafficLight [ x = 40, c = #61C554, rim = #4CAF45, ink = #145E14, sym = "zoom",
                on = { classroot.active || classroot.lightsHover }, showGlyph = { classroot.lightsHover },
                onMouseOver() { classroot.lightsHover = true },
                onMouseOut()  { classroot.lightsHover = false },
                onClick() { classroot.zoomToggle() },
                ],
            ],

        cap: Text [ x = center, y = center, fontSize = 13, fontWeight = semibold,
            textColor = { classroot.active ? this.theme.text : this.theme.textMuted },
            text = { classroot.title } ],

        // the separator under the title bar — present active OR not

        sep: View [ x = 0, y = 34, width = { parent.width }, height = 1, fill = { this.theme.line } ],
        ],

    // resize strips — every edge and corner macOS makes grabbable except the
    // top (the title bar owns it): left/right edges, bottom edge, and the two
    // bottom corners, each with its macOS cursor. Three unique shapes: ↔ for
    // either vertical edge, ↕ for the bottom, and the two diagonals for the
    // corners. 8px strips (was 6) and 16px corners (was 14) — easier to grab.

    edgeL: View [ width = 8, x = 0, y = 35, height = { parent.height - 51 }, cursor = "ew-resize",
        onMouseDown() { classroot.beginSize("l") },
        onMouseMove() { classroot.moveSize() },
        onMouseUp()   { classroot.sizeMode = "" },
        ],
    edgeR: View [ width = 8, x = { parent.width - 8 }, y = 35, height = { parent.height - 51 }, cursor = "ew-resize",
        onMouseDown() { classroot.beginSize("r") },
        onMouseMove() { classroot.moveSize() },
        onMouseUp()   { classroot.sizeMode = "" },
        ],
    edgeB: View [ height = 8, x = 16, y = { parent.height - 8 }, width = { parent.width - 32 }, cursor = "ns-resize",
        onMouseDown() { classroot.beginSize("b") },
        onMouseMove() { classroot.moveSize() },
        onMouseUp()   { classroot.sizeMode = "" },
        ],
    cornerBL: View [ width = 16, height = 16, x = 0, y = { parent.height - 16 }, cursor = "nesw-resize",
        onMouseDown() { classroot.beginSize("lb") },
        onMouseMove() { classroot.moveSize() },
        onMouseUp()   { classroot.sizeMode = "" },
        ],
    grip: View [ width = 16, height = 16, cursor = "nwse-resize",
        x = { parent.width - 16 }, y = { parent.height - 16 },
        onMouseDown() { classroot.beginSize("rb") },
        onMouseMove() { classroot.moveSize() },
        onMouseUp()   { classroot.sizeMode = "" },
        draw(d) {
            d.strokeStyle = this.theme.textFaint
            d.lineWidth = 1
            d.beginPath()
            d.moveTo(6, 14); d.lineTo(14, 6)
            d.moveTo(10, 14); d.lineTo(14, 10)
            d.stroke()
            },
        ],
    ]


// The lights match the captured Safari originals: hairline rim in a darker
// tone of the fill (never black), and the hover glyphs are Apple's DRAWN
// iconography in a dark tone of the same hue — thick rounded ×, − bar, and
// the fullscreen pair of triangles split along the "/" diagonal.

class TrafficLight extends View [ y = 0, width = 14, height = 14, cornerRadius = 7,
    c:   Color = #EC6A5E,
    rim: Color = #D25349,
    ink: Color = #7B1006,
    sym: string = "",                            // "close" | "min" | "zoom"
    on: boolean = false,                         // the window's active state, fed at the use site
    showGlyph: boolean = false,                  // bar-hover, fed at the use site

    // the rims are HAIRLINES (David's reference: "very thin and subtle") — a
    // half-pixel stroke, hue-toned when lit, barely-there grey when not

    fill = { this.on ? this.c : (this.root.darkMode ? 0x54545A : 0xD2D2D6) },
    stroke = { stroke(0.5, this.on && this.rim != null ? this.rim : 0x00000014) },

    g: View [ x = 0, y = 0, width = 14, height = 14,
        visible = { classroot.showGlyph && classroot.on },
        draw(d) {
            d.strokeStyle = classroot.ink
            d.fillStyle = classroot.ink
            d.lineCap = "round"
            if (classroot.sym == "close") {
                d.lineWidth = 1.6
                d.beginPath()
                d.moveTo(4.5, 4.5); d.lineTo(9.5, 9.5)
                d.moveTo(9.5, 4.5); d.lineTo(4.5, 9.5)
                d.stroke()
                }
            else if (classroot.sym == "min") {
                d.lineWidth = 1.8
                d.beginPath()
                d.moveTo(3.5, 7); d.lineTo(10.5, 7)
                d.stroke()
                }
            else if (classroot.sym == "zoom") {
                d.beginPath()
                d.moveTo(4.1, 4.1); d.lineTo(8.5, 4.1); d.lineTo(4.1, 8.5)
                d.closePath(); d.fill()
                d.beginPath()
                d.moveTo(9.9, 9.9); d.lineTo(5.5, 9.9); d.lineTo(9.9, 5.5)
                d.closePath(); d.fill()
                }
            },
        ],
    ]


// ── small drawn Finder iconography: the macOS folder, and the dog-eared page ─

class FolderIcon extends View [ width = 17, height = 13,
    draw(d) {
        const rr = (x, y, w, h, r) => {
            d.beginPath()
            d.moveTo(x + r, y)
            d.lineTo(x + w - r, y); d.arc(x + w - r, y + r, r, -Math.PI / 2, 0, false)
            d.lineTo(x + w, y + h - r); d.arc(x + w - r, y + h - r, r, 0, Math.PI / 2, false)
            d.lineTo(x + r, y + h); d.arc(x + r, y + h - r, r, Math.PI / 2, Math.PI, false)
            d.lineTo(x, y + r); d.arc(x + r, y + r, r, Math.PI, Math.PI * 1.5, false)
            d.closePath()
            }
        d.fillStyle = 0x4E9FEA
        rr(0, 0, 7.5, 4, 1.5); d.fill()              // the back tab
        d.fillStyle = 0x6AB2F5
        rr(0, 1.8, 17, 11, 1.5); d.fill()            // the body
        d.fillStyle = 0x8CC4F8
        rr(0, 1.8, 17, 3.2, 1.5); d.fill()           // the top lip highlight
        },
    ]


class FileIcon extends View [ width = 13, height = 16,
    draw(d) {
        d.fillStyle = 0xFFFFFF
        d.strokeStyle = 0xB4B4BA
        d.lineWidth = 1
        d.beginPath()
        d.moveTo(0.5, 0.5); d.lineTo(8.5, 0.5); d.lineTo(12.5, 4.5)
        d.lineTo(12.5, 15.5); d.lineTo(0.5, 15.5)
        d.closePath(); d.fill(); d.stroke()
        d.fillStyle = 0xDDDDE2                       // the dog-ear fold
        d.beginPath()
        d.moveTo(8.5, 0.5); d.lineTo(8.5, 4.5); d.lineTo(12.5, 4.5)
        d.closePath(); d.fill(); d.stroke()
        },
    ]


// ── Finder: a column browser over the repository's own documentation ─────────

