        ] }),
        ({ name: "Operational", files: [
            ({ name: "Getting started", path: "../../docs/operational/getting-started.md" }),
            ({ name: "Building", path: "../../docs/operational/building.md" }),
            ({ name: "The dev server", path: "../../docs/operational/dev-server.md" }),
            ({ name: "Flags", path: "../../docs/operational/flags.md" }),
