    // 2026-07-18): inside the strip, magnification TRACKS the pointer with no
    // visible lag; enter and exit each complete within ~one frame (≲100-150ms).
    // So `near` (the horizontal falloff) is an UNSPRUNG constraint — instant
    // response — and only the enter/exit ENVELOPE (the dock's `hot`, sprung at
    // ~100ms) animates. The earlier per-icon spring (~300ms) read as syrup.

    near: number = { Math.max(0, 1 - Math.abs(this.root.pointerX - this.cx0) / 150) },
    env: number = { this.parent.parent.hot },

    // real width: neighbors displace, the plate's edges push outward

    width  = { 48 * (1 + 0.5 * Math.pow(Math.max(0, this.near * this.env), 2)) },
