            ({ divider: true }),
            ({ id: "dark", label: this.root.darkMode ? "Light Appearance" : "Dark Appearance", key: "⌘K" }),
        ] }),
        ({ id: "file", label: "File", items: [
            ({ id: "new-finder", label: "New Finder Window", key: "⌘N" }),
            ({ id: "new-viewer", label: "New Viewer", key: "⌘O" }),
            ({ divider: true }),
            ({ id: "close", label: "Close Window", key: "⌘W", enabled: this.root.frontWin != null }),
        ] }),
    ] },

    bar: View [ x = 0, y = 0, width = { this.root.width }, height = 25, fill = { this.theme.surface }, opacity = 0.92,
        mb: MenuBar [ x = 12, menus = { this.root.menus },
            picked(id) { this.root.command(id) },
            ],
        clock: Text [ x = { parent.width - this.width - 14 }, y = center, fontSize = 13,
            textColor = { this.theme.text }, text = { this.root.clockText } ],
        ],

    // ── the dock ───────────────────────────────────────────────────────────

    dock: View [ height = 78,
        width = { this.plate.width },
        x = { (this.root.width - this.width) / 2 },
        y = { this.root.height - 82 },

